SELECT Template_ID, COUNT(*) AS usage_count
FROM Documents
GROUP BY Template_ID;

SELECT professional_id, role_code, email_address
FROM Professionals
WHERE professional_id NOT IN (
    SELECT DISTINCT professional_id
    FROM Treatments
    WHERE dog_id IN (
        SELECT dog_id
        FROM Dogs
    )
);

SELECT grade, COUNT(*) AS number_of_highschoolers
FROM Highschooler
GROUP BY grade;

SELECT grade, COUNT(*) AS count
FROM Highschooler
GROUP BY grade;

SELECT student_id, COUNT(friend_id) AS friend_count
FROM Friend
GROUP BY student_id;

SELECT Language, COUNT(*) AS number_of_channels
FROM TV_Channel
GROUP BY Language;

SELECT AVG(GNP) AS mean_gnp, SUM(Population) AS total_population
FROM country
WHERE GovernmentForm LIKE '%US territory%';
